import React from 'react';
import { TouchableOpacity, Text, StyleSheet, ViewStyle, StyleProp } from 'react-native';
import { typography } from '../styles/typography';
import { createTheme } from '../styles/theme';

const theme = createTheme();

interface ButtonProps {
  children: React.ReactNode;
  onPress?: () => void;
  disabled?: boolean;
  style?: StyleProp<ViewStyle>;
  variant?: 'primary' | 'outline';
  borderWidth?: number;
}

const Button: React.FC<ButtonProps> = ({ children, onPress, disabled, style, variant = 'primary', borderWidth }) => {
  const buttonStyle = [
    styles.button,
    variant === 'outline' && styles.outline,
    variant === 'outline' && borderWidth ? { borderWidth } : {},
    disabled && styles.buttonDisabled,
    style,
  ];
  return (
    <TouchableOpacity
      style={buttonStyle}
      onPress={onPress}
      disabled={disabled}
      activeOpacity={0.8}
    >
      {typeof children === 'string' ? <Text style={typography.button}>{children}</Text> : children}
    </TouchableOpacity>
  );
};

const styles = StyleSheet.create({
  button: {
    backgroundColor: '#000',
    borderRadius: 12,
    height: 48,
    alignItems: 'center',
    justifyContent: 'center',
    marginVertical: 8,
  },
  outline: {
    backgroundColor: '#fff',
    borderColor: '#000',
    borderWidth: 3,
  },
  buttonDisabled: {
    backgroundColor: theme.colors.textSecondary,
    opacity: 0.5,
  },
});

export default Button;
